mapper.select:
SELECT schema_name,digest,max(digest_text) digest_text,
       sum(delta_count) exec_count,sum(delta_timer_wait) total_timer_wait,
       sum(delta_rows_examined) rows_examined,sum(delta_lock_time) lock_time
  FROM metric_top_sql
 WHERE instance_id=#{instanceId} AND collect_time>=#{from} AND collect_time<=#{to}
 GROUP BY schema_name,digest ORDER BY total_timer_wait DESC LIMIT #{limit}

SELECT id,plan_hash,node_summary,captured_at FROM mysql_plan_history
 WHERE instance_id=#{instanceId} AND schema_name=#{schemaName} AND sql_hash=#{sqlHash}
 ORDER BY captured_at DESC LIMIT 1

SELECT id,schema_name,sql_hash,plan_hash,previous_plan_hash,plan_changed,plan_format,
       node_summary,risk_level,conclusion,captured_by,captured_at
  FROM mysql_plan_history
 WHERE instance_id=#{instanceId} AND captured_at>=#{from} AND captured_at<=#{to}
 ORDER BY captured_at DESC LIMIT #{limit}

SELECT id,schema_name,sql_hash,plan_hash,previous_plan_hash,plan_changed,plan_format,
       plan_json,node_summary,risk_level,conclusion,captured_by,captured_at
  FROM mysql_plan_history
 WHERE instance_id=#{instanceId} AND schema_name=#{schemaName} AND sql_hash=#{sqlHash}
 ORDER BY captured_at DESC LIMIT #{limit}
